import React from 'react';
import * as C from './style';
import * as Config from '../../config/moneyConfig'

function CardAdcs({ adicionais, origem }) {
    let address = `./${adicionais.nome}.jpg`
    let valor = Config.valueToString(adicionais.preco);
    return (
        <C.Card className='card' origem={origem}>
            <C.Panel origem={origem}>
                <C.Picture origem={origem} src={address}></C.Picture>
                <C.TitleProduto>{adicionais.nome}</C.TitleProduto>
            </C.Panel>
        </C.Card>
    )
}

export default CardAdcs
